'use strict';

const fs = require('fs');
const path = require('path');
const { allCustomers } = require('../core/customers.js');
const { AppError } = require('../lib/errors.js');
const config = require('../config.js');

async function exportCustomers(args) {
  const formatIndex = args.indexOf('--format');
  const format = formatIndex !== -1 ? args[formatIndex + 1] : undefined;

  if (!format || (format !== 'json' && format !== 'csv')) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  const records = allCustomers();

  fs.mkdirSync(config.outputDir, { recursive: true });

  const outPath = path.join(config.outputDir, `customers.${format}`);

  let content;
  if (format === 'json') {
    content = JSON.stringify(records, null, 2) + '\n';
  } else {
    const rows = records.map((c) => `${c.id},${c.name},${c.email}`);
    content = ['id,name,email', ...rows].join('\n') + '\n';
  }

  fs.writeFileSync(outPath, content, 'utf8');

  return [`exported customers to ${outPath}`];
}

module.exports = { exportCustomers };

